INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-7c9828ae-moex-00007', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-13504c0c', 'sub-retired-7c9828ae-01', NULL, 'single_choice', '「為了獲得更漂亮的羽毛而落去原有的羽毛，這有點像是學著每年自我更新，儘管 必須歷經一段艱困的時期才能達成。身為有別於鳥的人類，我們雖然會掉毛髮，但 並不了解這些換羽的階段——然而對我們人類來說，有時也必須換羽。在某些重大 的生命時刻——為愛心碎、哀悼、失業、遷居之際，我們必須改頭換面、變換衣著 或髮型以及生活作息。」 根據上文，下列何者最適合用來解釋人類的「換羽」？', '["調整後重新出發", "挑戰體能的極限", "思考後審慎行動", "把握當下的時光"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00008', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-13504c0c', 'sub-retired-7c9828ae-01', NULL, 'single_choice', '「『形破』（Deformation）是對既定的形的突破，要說是追求自由的人們所表現出 的念想也可以；也可以說是『未定型』或『未成形』，我想以容易理解的『奇數之 美』來稱之。『奇』並不是奇怪的意思，是與『偶』相對的『奇』，或『不完整』。」 下列選項，何者最貼近上文的觀點？', '["奇數的美，往往比偶數的美，來得更容易被看見", "勇於打破形式的框架限制，展現創作的自由意志", "形破，因為還不完整，故能取得最大的想像空間", "創作自由，就是要不斷地推陳出新，表現新形式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00009', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-13504c0c', 'sub-retired-7c9828ae-01', NULL, 'single_choice', '「2022 年，聊天機器人 ChatGPT 的出現引領了全球人工智慧的熱潮，但也帶來了 人們對就業和倫理的擔憂。關於就業，研究表明，在未來幾十年內，真正被取代的 工作僅占所有工作的10％左右。並非所有工作都會被完全自動化，而是某些特定任 務會被自動化。重要的是，我們需要關注人們是否具備與機器協作的技能，並提供 技能再造和適應新職場的支持。關於倫理問題，面對強大的人工智慧系統時，需要 思考如何合理應用它，避免不良利用。如何制定合理的使用原則，確保訓練和應用 符合實際需求。同時，也要關注可能的誤用，包括無意的落差和有意的濫用。解決 這些就業和倫理問題，需要的不僅是電腦工程專家，還需要涉及多個領域的專家， 如社會科學家、倫理學者和哲學家等。」 根據上文，下列選項何者最符合文意？', '["解決就業和倫理問題，端賴全球電腦工程專家的共同努力", "研究表明，在未來幾十年內，所有工作都會被完全自動化取代", "人工智慧帶來就業和倫理的擔憂，需要關注技能再造和適應新職場", "強大人工智慧系統的應用，需要遵循傳統的使用原則，以防止不良利用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00010', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-13504c0c', 'sub-retired-7c9828ae-01', NULL, 'single_choice', '「大企業為什麼凡事都得曠日廢時？主要是官僚作風的無形掣肘——每件事都必 須按照規定與流程完成。許多企業主管表示希望從官僚作風轉變為『菁英精神』， 置人才與構想於一切之上。但事實證明，菁英精神可以跟官僚作風一樣拖拖拉拉， 一樣著眼於內部。我們在最古老的菁英體系——大學——中工作，儘管我們痛恨規 則，卻熱愛事事針鋒相對。所以，你需要的是著重於行動。在實務上，簡化公司正 式流程、減少跨部門委員會的數量與規模，以靈活、敏捷的小型團隊模式取而代之； 這些團隊獲得授權，可以快速直接因應顧客需求。打比方，你不妨將這些團隊想像 成軍方派入敵區作戰的特殊部隊。」 根據上文，下列敘述何者正確？', '["官僚作風可以靈活地省略各種規定與流程", "菁英精神重視人才與構想，而且行動迅速", "菁英精神未必能克服官僚作風在處理事務上的效率問題", "團體組織更見效率，流程簡化時擴大跨部會委員會規模"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00011', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '有關禁止法律溯及既往原則與過渡條款，下列敘述何者正確？', '["限制基本權利之法律，若適用於該法律施行前已終結之事件，乃憲法所絕對不許", "基於禁止法律溯及既往原則，對人民有利之法律，不得適用於該法律施行前已終結之事件", "基於禁止法律溯及既往原則，法律不得適用於施行前已發生，施行後繼續存在之法律關係", "立法者制定新法，若應設卻未設過渡條款適度排除新法之適用範圍，此一法律漏洞仍有由司法機關 補充之可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00012', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '依據憲法增修條文規定，有關基本國策，國家對於公營金融機構之管理，應本下列何種原則？', '["社會平等", "企業化經營", "組織現代化", "提升競爭力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00013', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '政黨為人民之政治性結社團體，有關政黨與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民得自由選擇加入或退出特定政黨", "政黨財產之使用、收益及處分，受財產權及結社自由之憲法保障", "政黨就其存續、內部之組織與運作以及對外活動等，不受國家恣意之干預", "政黨於民主政治運作有其重要性與必要性，故國家不得以任何理由解散政黨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00014', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '所得稅法將軍人、國小教師原本免繳所得稅之規定，改為有所得即應繳稅，屬於憲法平等原則對何國 家機關的拘束？', '["對監察院之拘束", "對司法院之拘束", "對行政院之拘束", "對立法院之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00015', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '下列何者與憲法第15條保障之工作權無關？', '["老年年金制度", "限制醫師藥品調劑權", "勞資爭議處理機制", "對童工的相關保護規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00016', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '依司法院釋字第490號解釋，有關「中華民國男子依法皆有服兵役之義務」規定，下列敘述何者 錯誤？', '["基於憲法平等原則的要求，應將女子排除於兵役義務之外", "人民履行兵役義務的方式，應由立法者決定", "人民有服兵役之義務，此為憲法明文規定", "關於服兵役之重要事項，立法者應斟酌國家安全之需要，予以規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL)
